import{_ as e,o as i,c as t,a0 as s}from"./chunks/framework.DTwdCQre.js";const k=JSON.parse('{"title":"LSP 集成","description":"LSP 健康检查、能力门控、诊断和降级行为","frontmatter":{"title":"LSP 集成","description":"LSP 健康检查、能力门控、诊断和降级行为"},"headers":[],"relativePath":"zh/extension/lsp.md","filePath":"zh/extension/lsp.md","lastUpdated":1777729439000}'),d={name:"zh/extension/lsp.md"};function l(o,a,n,r,h,p){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="lsp-集成" tabindex="-1">LSP 集成 <a class="header-anchor" href="#lsp-集成" aria-label="Permalink to &quot;LSP 集成&quot;">​</a></h1><blockquote><p><strong>状态：实验性功能（v0.3 产品化中）</strong> — LSP 客户端和健康检查门控已经实现，但只有配置的服务器通过健康检查后，才会暴露 LSP 代码智能能力。<code>go-code doctor --offline</code> 只报告本地配置状态，不发起网络探测。</p></blockquote><p>go-code 将 Language Server Protocol (LSP) 作为可选扩展能力，用于代码智能。未配置 LSP 服务器时，核心提示词流程、TUI、内置工具、MCP 工具、Hooks 和 Skills 仍会继续工作。</p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>LSP 健康检查通过 <code>GO_CODE_LSP_URL</code> 显式启用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GO_CODE_LSP_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:8080/lsp&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>未设置该变量时，LSP 会被视为 unavailable，而不是 failed。</p><h2 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to &quot;健康检查&quot;">​</a></h2><p>LSP gate 会先发送 <code>initialize</code> 请求，再决定是否暴露代码智能操作。只有初始化成功的服务器才会被视为健康。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>离线诊断不会连接服务器：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --offline</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>常见 doctor 状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td><code>[SKIP] lsp: not configured</code></td><td>未设置 <code>GO_CODE_LSP_URL</code>。</td></tr><tr><td><code>[SKIP] lsp: configured ... skipped by --offline</code></td><td>已配置 LSP URL，但 <code>--offline</code> 跳过了网络健康检查。</td></tr><tr><td><code>[PASS] lsp</code></td><td>初始化成功。</td></tr><tr><td><code>[FAIL] lsp</code></td><td>已配置服务器初始化失败或返回无效响应。</td></tr></tbody></table><h2 id="能力门控" tabindex="-1">能力门控 <a class="header-anchor" href="#能力门控" aria-label="Permalink to &quot;能力门控&quot;">​</a></h2><p>go-code 只会在健康检查通过后暴露 LSP 操作。当前 gate 识别：</p><table tabindex="0"><thead><tr><th>操作</th><th>LSP capability</th></tr></thead><tbody><tr><td>Diagnostics</td><td><code>publishDiagnosticsProvider</code></td></tr><tr><td>Symbols</td><td><code>workspaceSymbolProvider</code> 或 <code>documentSymbolProvider</code></td></tr><tr><td>Definitions</td><td><code>definitionProvider</code></td></tr><tr><td>References</td><td><code>referencesProvider</code></td></tr><tr><td>Hover</td><td><code>hoverProvider</code></td></tr></tbody></table><p>如果服务器未配置、初始化失败，或没有声明某项能力，对应操作不会被暴露。</p><h2 id="trace-证据" tabindex="-1">Trace 证据 <a class="header-anchor" href="#trace-证据" aria-label="Permalink to &quot;Trace 证据&quot;">​</a></h2><p>LSP 健康检查结果会作为非致命 extension 事件写入 session trace：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;extension&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lsp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;event&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;health_check&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;unavailable&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>成功检查会包含可暴露操作，以及服务器返回的身份信息。失败检查会记录初始化错误，但不会阻断无关工作流。</p><h2 id="降级行为" tabindex="-1">降级行为 <a class="header-anchor" href="#降级行为" aria-label="Permalink to &quot;降级行为&quot;">​</a></h2><ul><li>未配置 LSP：继续运行，但不暴露 LSP 操作。</li><li>离线 doctor：只报告配置状态，不访问网络。</li><li>初始化失败：核心 prompt/tool 工作流保持可用，并通过 diagnostics 和 trace evidence 报告 LSP 失败。</li><li>缺少服务器能力：不暴露对应操作。</li></ul><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h2><p>当前覆盖位于 <code>internal/lsp/gate_test.go</code>，证明 unavailable、初始化成功、初始化失败、trace 记录、以及 operation gating 行为。</p><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="./mcp.html">MCP 集成</a></li><li><a href="./hooks.html">Hooks 系统</a></li><li><a href="./skills.html">Skills 系统</a></li></ul>',28)])])}const u=e(d,[["render",l]]);export{k as __pageData,u as default};
